// Kleene 3-valued logic implementation
class KleeneLogic {
  static VALUES = { T: true, F: false, U: 'unknown' };

  static NOT(x) {
    return x === 'U' ? 'U' : !x;
  }

  static AND(x, y) {
    if (x === 'F' || y === 'F') return 'F';
    if (x === 'U' || y === 'U') return 'U';
    return 'T';
  }

  static OR(x, y) {
    if (x === 'T' || y === 'T') return 'T';
    if (x === 'U' || y === 'U') return 'U';
    return 'F';
  }

  static XOR(x, y) {
    return this.OR(this.AND(x, this.NOT(y)), this.AND(this.NOT(x), y));
  }

  static IMPLIES(x, y) {
    if (x === 'F') return 'T';
    if (x === 'U' || y === 'U') return 'U';
    return y;
  }
}
```

